// Parse queueItem — it may arrive as a JSON string or an object
const raw = $input.item.json;
let queueItem;
if (typeof raw.queueItem === 'string') {
  queueItem = JSON.parse(raw.queueItem);
} else if (raw.queueItem && typeof raw.queueItem === 'object') {
  queueItem = raw.queueItem;
} else {
  throw new Error('send-email sub-workflow: queueItem missing from input');
}

// ── Apply DEFAULT_FROM_* env var fallbacks ────────────────────
// Allows campaigns to skip setting from_email at the DB level.
const defaultFromEmail = process.env.DEFAULT_FROM_EMAIL || 'noreply@example.com';
const defaultFromName  = process.env.DEFAULT_FROM_NAME  || 'Drip Engine';
queueItem.from_email      = queueItem.from_email      || defaultFromEmail;
queueItem.from_name       = queueItem.from_name       || defaultFromName;
queueItem.reply_to_email  = queueItem.reply_to_email  || queueItem.from_email;

// Validate essential fields (from_email is now guaranteed)
const required = ['queue_id', 'email', 'campaign_id', 'contact_id', 'step_order',
                  'subject', 'template_body', 'hourly_limit'];
const missing = required.filter(k => queueItem[k] === undefined || queueItem[k] === null);
if (missing.length > 0) {
  throw new Error(`send-email: missing required fields: ${missing.join(', ')}`);
}
return [{ json: { queueItem } }];

// ── Rate Limit Check using Workflow Static Data ──────────────
// Static data persists across executions within the same workflow.
// Key: rl_<campaignId>  → current hour send count
// Key: rl_ts_<campaignId> → timestamp when window started

const data = $getWorkflowStaticData('global');
const item = $input.item.json.queueItem;
const campaignId  = item.campaign_id;
const hourlyLimit = Number(item.hourly_limit) || 100;
const now = Date.now();

const windowKey = `rl_${campaignId}`;
const tsKey     = `rl_ts_${campaignId}`;

// Reset window if 1 hour has elapsed
if (!data[tsKey] || (now - data[tsKey]) > 3_600_000) {
  data[windowKey] = 0;
  data[tsKey]     = now;
}

if (data[windowKey] >= hourlyLimit) {
  console.log(`[Rate Limit] Campaign ${campaignId}: limit ${hourlyLimit}/hr reached. Skipping.`);
  return [{ json: { rateLimited: true, queueItem: item } }];
}

data[windowKey]++;
console.log(`[Rate Limit] Campaign ${campaignId}: ${data[windowKey]}/${hourlyLimit} this hour.`);
return [{ json: { rateLimited: false, count: data[windowKey], queueItem: item } }];

// ── Template Personalisation + HMAC-signed Unsubscribe Token ─
const crypto = require('crypto');

const item     = $input.item.json.queueItem;
const metadata = typeof item.metadata === 'string'
  ? JSON.parse(item.metadata)
  : (item.metadata || {});

const contact = { ...metadata, email: item.email };

// Render template — collect missing variables
const missing = [];
const renderVar = (template) => template.replace(/\{\{(\w+)\}\}/g, (_, k) => {
  if (contact[k] === undefined) { missing.push(k); return ''; }
  return String(contact[k]);
});

const renderedSubject = renderVar(item.subject);
const renderedBody    = renderVar(item.template_body);

if (missing.length > 0) {
  throw new Error(`Missing template variables: ${[...new Set(missing)].join(', ')}`);
}

// Build HMAC-signed base64url unsubscribe token
const payload = JSON.stringify({
  email: item.email,
  cid:   item.campaign_id,
  iat:   Math.floor(Date.now() / 1000)
});
const secret = process.env.UNSUB_HMAC_SECRET || 'change-me-in-env';
const hmac   = crypto.createHmac('sha256', secret)
  .update(payload)
  .digest('base64url');

const tokenPayload = Buffer.from(payload).toString('base64url');
const unsubToken   = `${tokenPayload}.${hmac}`;

const n8nUrl    = process.env.WEBHOOK_URL || 'https://YOUR_N8N_URL';
const unsubLink = `${n8nUrl}/webhook/unsubscribe?t=${unsubToken}`;

const unsubFooter = `
<p style="font-size:11px;color:#999;margin-top:32px;">
  You are receiving this because you subscribed to our list.<br>
  <a href="${unsubLink}">Unsubscribe</a>
</p>`;

const finalBody = renderedBody + unsubFooter;

return [{ json: {
  ...item,
  renderedSubject,
  renderedBody: finalBody,
  unsubToken,
  unsubLink
} }];

