// Extract ESP messageId from Brevo response
const resp = $input.item.json;
const messageId = resp.messageId || resp.message_id || resp.MessageId || null;
if (!messageId) {
  console.warn('[Send Email] Warning: Brevo did not return a messageId. Response:', JSON.stringify(resp));
}
const prev = $('Code: Personalise Email').item.json;
return [{ json: { ...prev, esp_message_id: messageId, brevoResponse: resp } }];

// Merge next-step data with the sent-email context
const prevItem = $('PG: Log Sent Event').item.json;
const nextSteps = $input.all();
if (nextSteps.length === 0 || !nextSteps[0].json.id) {
  return [{ json: { ...prevItem, nextStep: null } }];
}
return [{ json: { ...prevItem, nextStep: nextSteps[0].json } }];
